package com.chaobo.scm.supplier.infrastructure.persistence.quality;import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.quality.*;import com.chaobo.scm.supplier.domain.quality.*;import org.springframework.stereotype.Repository;import java.util.*;
@Repository public class MyBatisSupplierQualityIssueAdapter implements SupplierQualityIssueRepository,SupplierQualityIssueReadModelPort {private final SupplierQualityIssueMapper mapper;public MyBatisSupplierQualityIssueAdapter(SupplierQualityIssueMapper mapper){this.mapper=mapper;}public Optional<SupplierQualityIssueAggregate> findById(long id){var r=mapper.find(id);return r==null?Optional.empty():Optional.of(SupplierQualityIssueAggregate.rehydrate(r.id(),r.no(),r.supplierId(),r.sourceType(),r.sourceNo(),r.issueType(),r.severity(),r.description(),r.status(),r.deadline(),r.plan(),r.verification(),r.version()));}public void save(SupplierQualityIssueAggregate a,long operator){var r=row(a);if(mapper.find(a.id())==null)mapper.insert(r,operator);else if(mapper.update(r,a.version()-1,operator)!=1)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"质量问题已被更新");}public Optional<SupplierQualityIssueView> detail(long id){var r=mapper.find(id);return r==null?Optional.empty():Optional.of(view(r));}public PageResult<SupplierQualityIssueView> page(Long supplierId,Integer status,Integer severity,int page,int size){return new PageResult<>(page,size,mapper.count(supplierId,status,severity),mapper.page(supplierId,status,severity,(page-1)*size,size).stream().map(this::view).toList());}public List<Long> overdueIds(){return mapper.overdueIds();}private SupplierQualityIssueMapper.Row row(SupplierQualityIssueAggregate a){return new SupplierQualityIssueMapper.Row(a.id(),a.no(),a.supplierId(),a.sourceType(),a.sourceNo(),a.issueType(),a.severity(),a.description(),a.status().code(),a.deadline(),a.plan(),a.verification(),a.version());}private SupplierQualityIssueView view(SupplierQualityIssueMapper.Row r){var s=QualityIssueStatus.fromCode(r.status());return new SupplierQualityIssueView(r.id(),r.no(),r.supplierId(),r.sourceType(),r.sourceNo(),r.issueType(),r.severity(),r.description(),s.code(),s.label(),r.deadline(),r.plan(),r.verification(),r.version());}}
